{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Region Sync Manager\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Manage and collaborate on REAPER regions with staged editing and CSV workflows.\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel1 \b \fs32 Features\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Safe staged region editing\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab CSV import and export\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab UID-based diff and 3-way merge\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Region QC and bulk tools\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Automatic backups and crash-recovery drafts\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Saved window geometry and diagnostic logs\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab English and Korean interface\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel1 \b \fs32 Requirements\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab REAPER\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab ReaImGui\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab js_ReaScriptAPI is optional for native file dialogs\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab REAPER 7.62 or newer is recommended for native hidden-region support\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Tested target: REAPER 7.76\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel1 \b \fs32 License\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Copyright (c) 2026 Yoon-Soo Lee. All rights reserved. Redistribution, resale, or secondary distribution requires written permission.\par}
}

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}{\f1 \fmodern Courier;}}
