{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 Sound Lib Manager Pro\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Manage sound-library keywords and tags quickly in REAPER.\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel1 \b \fs32 Features\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Real-time multi-word search\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Keyword and tag editing\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Favorites and usage-based sorting\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Smart Collections and AND/OR tag filters\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Automatic tag suggestions\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Media Explorer handoff\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Safe delete with an 8-second undo window\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab External JSON storage with rotating backups\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab CSV import and export\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab English and Korean interface\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel1 \b \fs32 Requirements\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab REAPER\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab ReaImGui 0.9.2 or later\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab js_ReaScriptAPI is optional and enables direct Media Explorer search-history capture\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel1 \b \fs32 License\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Copyright (c) 2026 Yoon-Soo Lee. All rights reserved. Redistribution, resale, or secondary distribution requires written permission.\par}
}

