{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel0 \b \fs36 YSL ReaPack\par}
{\pard \ql \f0 \sa180 \li0 \fi0 REAPER tools by {\b Yoon-Soo Lee}.\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel1 \b \fs32 Packages\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel2 \b \fs28 Region Sync Manager\par}
{\pard \ql \f0 \sa180 \li0 \fi0 A region collaboration and management tool for REAPER.\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Staged region editing\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab CSV import and export\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab UID-based diff and 3-way merge\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Region QC and bulk tools\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Automatic backups and crash-recovery drafts\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab English and Korean interface\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel2 \b \fs28 Sound Lib Manager Pro\par}
{\pard \ql \f0 \sa180 \li0 \fi0 A keyword and tag manager for sound libraries.\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Fast keyword and tag search\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Favorites, usage sorting, and Smart Collections\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Automatic tag suggestions\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Media Explorer handoff\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab External JSON storage and rotating backups\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab CSV import and export\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab 8-second delete undo\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab English and Korean interface\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel1 \b \fs32 Requirements\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab REAPER\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab ReaPack\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab ReaImGui\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab {\f1 js_ReaScriptAPI} is optional for Region Sync Manager file dialogs\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel1 \b \fs32 Install with ReaPack\par}
{\pard \ql \f0 \sa180 \li0 \fi0 After this repository has been uploaded to GitHub and the {\f1 deploy} workflow has finished successfully, import this URL in REAPER:\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \f1 https://raw.githubusercontent.com/YOUR_GITHUB_USERNAME/YSL-ReaPack/main/index.xml\par}
{\pard \ql \f0 \sa180 \li0 \fi0 In REAPER:\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 1.\tx360\tab Open {\b Extensions > ReaPack > Import repositories}\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 2.\tx360\tab Paste the URL above after replacing {\f1 YOUR_GITHUB_USERNAME}\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 3.\tx360\tab Synchronize packages\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 4.\tx360\tab Search for {\f1 Region Sync Manager} or {\f1 Sound Lib Manager Pro}\sa180\par}
{\pard \ql \f0 \sa180 \li0 \fi0 \outlinelevel1 \b \fs32 Repository maintenance\par}
{\pard \ql \f0 \sa180 \li0 \fi0 The GitHub Actions workflows validate the script metadata and automatically rebuild {\f1 index.xml} with the official {\f1 reapack-index} tool whenever the {\f1 main} or {\f1 master} branch is updated.\par}
{\pard \ql \f0 \sa180 \li0 \fi0 For a new public release:\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 1.\tx360\tab Update the script's {\f1 @version}\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 2.\tx360\tab Update {\f1 @changelog}\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 3.\tx360\tab Commit and push\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 4.\tx360\tab Wait for the {\f1 deploy} workflow to finish\sa180\par}
}
